import * as d3 from "d3"
import { useEffect, useMemo, useRef, useState } from "react"

const ChartDraw = (props) => {
	const chartRef = useRef(null);

	const [width, setWidth] = useState(0);
	const [height, setHeight] = useState(0);

	useEffect(() => {
        const svg = d3.select(chartRef.current);
        setWidth(parseFloat(svg.style("width")));
		setHeight(parseFloat(svg.style("height")));
    }, []);

	const margin = {
		top: 10,
		bottom: 60,
		left: 40,
		right: 10
	};

    const boundsWidth = width - margin.left - margin.right;
    const boundsHeight = height - margin.top - margin.bottom;

	const activeSeries = useMemo(() => {
		const series = [
			{ enabled: props.oy[0], index: 1, color: "red", className: "dot-max" },
			{ enabled: props.oy[1], index: 0, color: "blue", className: "dot-min" }
		];

		return series.filter(item => item.enabled);
	}, [props.oy]);

	const activeValues = useMemo(() => {
		return activeSeries.flatMap(series =>
			props.data.map(item => item.values[series.index])
		);
	}, [activeSeries, props.data]);

	const [minValue, maxValue] = activeValues.length > 0
		? d3.extent(activeValues)
		: [0, 0];

	const scaleX = useMemo(() => {
        return d3
            .scaleBand()
            .domain(props.data.map(d => d.labelX))
            .range([0, boundsWidth]);
    }, [props.data, boundsWidth]);

    const scaleY = useMemo(() => {
		const lowerBound = minValue === maxValue ? minValue - 1 : minValue * 0.85;
		const upperBound = minValue === maxValue ? maxValue + 1 : maxValue * 1.1;

        return d3
            .scaleLinear()
            .domain([lowerBound, upperBound])
            .range([boundsHeight, 0]);
    }, [boundsHeight, minValue, maxValue]);

	useEffect(() => {
        const svg = d3.select(chartRef.current);
        svg.selectAll("*").remove();

		if (width === 0 || height === 0 || props.data.length === 0 || activeSeries.length === 0) {
			return;
		}

		svg
			.append("rect")
			.attr("x", margin.left)
			.attr("y", margin.top)
			.attr("width", boundsWidth)
			.attr("height", boundsHeight)
			.style("fill", "lightgrey");

        const xAxis = d3.axisBottom(scaleX);
        svg
			.append("g")
            .attr("transform", `translate(${margin.left}, ${height - margin.bottom})`)
            .call(xAxis)
            .selectAll("text")
            .style("text-anchor", "end")
            .attr("dx", "-.8em")
            .attr("dy", ".15em")
            .attr("transform", "rotate(-30)");

        const yAxis = d3.axisLeft(scaleY);
        svg
			.append("g")
            .attr("transform", `translate(${margin.left}, ${margin.top})`)
            .call(yAxis);

		activeSeries.forEach(series => {
			svg
				.selectAll(`.${series.className}`)
				.data(props.data)
				.enter()
				.append("circle")
				.attr("class", series.className)
				.attr("r", 5)
				.attr("cx", d => scaleX(d.labelX) + scaleX.bandwidth() / 2)
				.attr("cy", d => scaleY(d.values[series.index]))
				.attr("transform", `translate(${margin.left}, ${margin.top})`)
				.style("fill", series.color);
		});
    }, [
		activeSeries,
		boundsHeight,
		boundsWidth,
		height,
		margin.bottom,
		margin.left,
		margin.top,
		props.data,
		scaleX,
		scaleY,
		width
	]);

    return (
      <svg ref={chartRef}></svg>
	)
}

export default ChartDraw
